import{_ as p,c as t,o as e,d as r}from"./app.65b10671.js";var a="/assets/248bbae02f71fac8aefbe437087d11c3.f427a0ea.jpg",s="/assets/a19ed81949d1b5235899acd96365b730.67539fa9.jpg",o="/assets/e4f8d6f02da512b463e0ff5665a2fdaa.3205af90.jpg",i="/assets/8bfac210b1af88e1862e8c84c05386b4.67a99041.jpg",n="/assets/14ba22a3e25c41711d7e17eb0678e504.4436a58e.jpg",c="/assets/5b0fef890c4204df7c409dbc97821f7d.ad519658.jpg",_="/assets/170bb32cc8786c4d698eecc0a06d8b64.03dd9817.jpg",d="/assets/825594e3a3cecdda5e654cbceb20e80c.2619813a.jpg";const y='{"title":"\u0421\u0432\u043E\u0438\u043C\u0438 \u0440\u0443\u043A\u0430\u043C\u0438: \u043A\u0430\u043A \u0443\u0441\u0442\u0440\u043E\u0435\u043D \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u0439 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433 \u0434\u043B\u044F \u043B\u044E\u0431\u0438\u0442\u0435\u043B\u0435\u0439 \u0438 \u043F\u0440\u043E\u0444\u0435\u0441\u0441\u0438\u043E\u043D\u0430\u043B\u043E\u0432","description":"","frontmatter":{"title":"\u0421\u0432\u043E\u0438\u043C\u0438 \u0440\u0443\u043A\u0430\u043C\u0438: \u043A\u0430\u043A \u0443\u0441\u0442\u0440\u043E\u0435\u043D \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u0439 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433 \u0434\u043B\u044F \u043B\u044E\u0431\u0438\u0442\u0435\u043B\u0435\u0439 \u0438 \u043F\u0440\u043E\u0444\u0435\u0441\u0441\u0438\u043E\u043D\u0430\u043B\u043E\u0432","date":"2017-05-23","cover":"Dar-Truda.jpg"},"headers":[],"relativePath":"theory/repost/coworking-dar/index.md"}',g={},l=r('<p><strong>\u041C\u043D\u043E\u0433\u0438\u0435 \u0436\u0438\u0442\u0435\u043B\u0438 \u0431\u043E\u043B\u044C\u0448\u043E\u0433\u043E \u0433\u043E\u0440\u043E\u0434\u0430 \u0445\u043E\u0442\u0435\u043B\u0438 \u0431\u044B \u0432\u0440\u0435\u043C\u044F \u043E\u0442 \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0447\u0442\u043E-\u0442\u043E \u0434\u0435\u043B\u0430\u0442\u044C \u0441\u0432\u043E\u0438\u043C\u0438 \u0440\u0443\u043A\u0430\u043C\u0438. \u0418 \u043C\u043D\u043E\u0433\u0438\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0430, \u0440\u0430\u0431\u043E\u0442\u0430\u044E\u0449\u0438\u0435 \u0441 \u0434\u0435\u0440\u0435\u0432\u043E\u043C \u0438\u043B\u0438 \u043C\u0435\u0442\u0430\u043B\u043B\u043E\u043C, \u0445\u043E\u0442\u0435\u043B\u0438 \u0431\u044B \u0437\u0430\u043F\u0443\u0441\u0442\u0438\u0442\u044C \u0441\u0432\u043E\u0451 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0441\u0442\u0432\u043E. \u0411\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0438\u0437 \u043D\u0438\u0445 \u043D\u0435 \u043C\u043E\u0433\u0443\u0442 \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u044D\u0442\u043E\u0433\u043E \u0438\u0437-\u0437\u0430 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u044F \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439. \u041D\u043E \u0432\u044B\u0445\u043E\u0434 \u0435\u0441\u0442\u044C \u2013 \u043F\u043E\u0439\u0442\u0438 \u0432 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0443\u044E \u0438 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u0430\u0442\u044C \u0441\u0432\u043E\u0451 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0441\u0442\u0432\u043E \u0442\u0430\u043C. \u0422\u0430\u043A, \u043C\u043E\u0441\u043A\u043E\u0432\u0441\u043A\u0438\u0439 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u0439 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433 \xAB\u0414\u0430\u0440 \u0442\u0440\u0443\u0434\u0430\xBB \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u0435\u0442 \u0432\u0441\u0435\u043C \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u043C \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0435 \u0441\u043E \u0432\u0441\u0435\u0439 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0439 \u0438\u043D\u0444\u0440\u0430\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u043E\u0439. \u041E \u0442\u043E\u043C, \u043F\u043E\u0447\u0435\u043C\u0443 \u0440\u0443\u0447\u043D\u043E\u0439 \u0442\u0440\u0443\u0434 \u0441\u043D\u043E\u0432\u0430 \u0432 \u043C\u043E\u0434\u0435, \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u0430\u043B \u0440\u0435\u0437\u0438\u0434\u0435\u043D\u0442 \xAB\u0414\u0430\u0440\u0430 \u0442\u0440\u0443\u0434\u0430\xBB \u0420\u043E\u043C\u0430\u043D \u0411\u043E\u043D\u0434\u0430\u0440\u0435\u0432.</strong></p><h4 id="\u0434\u043E\u0441\u044C\u0435" tabindex="-1">\u0414\u043E\u0441\u044C\u0435 <a class="header-anchor" href="#\u0434\u043E\u0441\u044C\u0435" aria-hidden="true">#</a></h4><p><strong>\u0420\u043E\u043C\u0430\u043D \u0411\u043E\u043D\u0434\u0430\u0440\u0435\u0432</strong>, 38 \u043B\u0435\u0442, \u0440\u0435\u0437\u0438\u0434\u0435\u043D\u0442 \u0438 \u043A\u043E\u043E\u0440\u0434\u0438\u043D\u0430\u0442\u043E\u0440 \u043F\u043E \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044E \u043C\u043E\u0441\u043A\u043E\u0432\u0441\u043A\u043E\u0439 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439\xA0 <a href="http://dartruda.ru/" class="external-link" target="_blank" rel="noopener noreferrer"><strong>\xAB\u0414\u0430\u0440 \u0442\u0440\u0443\u0434\u0430\xBB</strong></a>. \u0412 2001 \u0433\u043E\u0434\u0443 \u043E\u043A\u043E\u043D\u0447\u0438\u043B \u041C\u0413\u0422\u0423 \u041C\u0410\u041C\u0418 \u043F\u043E \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \xAB\u0438\u043D\u0436\u0435\u043D\u0435\u0440-\u0434\u0438\u0437\u0430\u0439\u043D\u0435\u0440\xBB. \u0420\u0430\u0431\u043E\u0442\u0430\u043B \u0430\u0432\u0442\u043E\u043C\u043E\u0431\u0438\u043B\u044C\u043D\u044B\u043C \u0436\u0443\u0440\u043D\u0430\u043B\u0438\u0441\u0442\u043E\u043C, \u0432 2012 \u0433\u043E\u0434\u0443 \u0441\u043E\u0437\u0434\u0430\u043B \u0441\u0432\u043E\u0439 \u043C\u0435\u0431\u0435\u043B\u044C\u043D\u044B\u0439 \u043F\u0440\u043E\u0435\u043A\u0442 SitUp, \u0437\u0430\u043D\u044F\u043B\u0441\u044F \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u043C \u0434\u0435\u043B\u043E\u043C \u0438 \u0441\u0442\u0430\u043B \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u043C \u043A\u043B\u0438\u0435\u043D\u0442\u043E\u043C \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439, \u0430 \u043F\u043E\u0437\u0436\u0435 \u2013 \u0435\u0451 \u0441\u043E\u0442\u0440\u0443\u0434\u043D\u0438\u043A\u043E\u043C. \u041E\u0441\u043D\u043E\u0432\u0430\u0442\u0435\u043B\u0438 \u0438 \u0441\u043E\u0432\u043B\u0430\u0434\u0435\u043B\u044C\u0446\u044B \u043F\u0440\u043E\u0435\u043A\u0442\u0430 \xAB\u0414\u0430\u0440 \u0442\u0440\u0443\u0434\u0430\xBB -\xA0<strong>\u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D \u0421\u043A\u0432\u043E\u0440\u0446\u043E\u0432</strong>\xA0\u0438\xA0<strong>\u041E\u043B\u0435\u0433 \u0424\u0430\u0440\u0430\u0434\u0436\u0443\u043B\u043B\u0430\u0435\u0432</strong>.</p><p><img src="'+a+'" alt="" title="\u0420\u043E\u043C\u0430\u043D \u0411\u043E\u043D\u0434\u0430\u0440\u0435\u0432"> <em>\u0420\u043E\u043C\u0430\u043D \u0411\u043E\u043D\u0434\u0430\u0440\u0435\u0432</em></p><p><strong>\u041E\u0442 \u043A\u043E\u043C\u043F\u044C\u044E\u0442\u0435\u0440\u0430 \u2013 \u043A \u0441\u0442\u0430\u043D\u043A\u0443</strong></p><p>\u0418\u0434\u0435\u044F \u0441\u043E\u0437\u0434\u0430\u0442\u044C \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0443\u044E \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0438\u0442 \u0433\u0440\u0430\u0444\u0438\u0447\u0435\u0441\u043A\u043E\u043C\u0443 \u0434\u0438\u0437\u0430\u0439\u043D\u0435\u0440\u0443 \u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D\u0443 \u0421\u043A\u0432\u043E\u0440\u0446\u043E\u0432\u0443. \u0412 2005 \u0433\u043E\u0434\u0443 \u0432\u044B\u043F\u0443\u0441\u043A\u043D\u0438\u043A \u0423\u0440\u0413\u0423 \u043F\u043E\u043D\u044F\u043B, \u0447\u0442\u043E \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u0445\u043E\u0447\u0435\u0442 \u043F\u0440\u043E\u0441\u0438\u0436\u0438\u0432\u0430\u0442\u044C \u043F\u0435\u0440\u0435\u0434 \u043A\u043E\u043C\u043F\u044C\u044E\u0442\u0435\u0440\u043E\u043C, \u0430 \u0445\u043E\u0447\u0435\u0442 \u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u0440\u0443\u043A\u0430\u043C\u0438. \u0421\u043D\u0430\u0447\u0430\u043B\u0430 \u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D \u0443\u0441\u0442\u0440\u043E\u0438\u043B\u0441\u044F \u043D\u0430 \u0441\u0442\u0440\u043E\u0439\u043A\u0443, \u0433\u0434\u0435 \u043F\u0440\u043E\u0448\u0451\u043B \u043F\u0443\u0442\u044C \u043E\u0442 \u0440\u0430\u0437\u043D\u043E\u0440\u0430\u0431\u043E\u0447\u0435\u0433\u043E \u0434\u043E \u043F\u0440\u043E\u0440\u0430\u0431\u0430, \u0430 \u043F\u043E\u0437\u0436\u0435 \u0432\u0441\u0435\u0440\u044C\u0451\u0437 \u0437\u0430\u043D\u044F\u043B\u0441\u044F \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u043C \u0434\u0435\u043B\u043E\u043C. \u0412 \u0442\u043E\u0442 \u043C\u043E\u043C\u0435\u043D\u0442 \u043E\u043D \u0441\u043E\u0442\u0440\u0443\u0434\u043D\u0438\u0447\u0430\u043B \u0441 \u043D\u0435\u043E\u0431\u044B\u0447\u043D\u044B\u043C \u0434\u043B\u044F \u0442\u043E\u0433\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u043C\u043E\u0441\u043A\u043E\u0432\u0441\u043A\u0438\u043C \u043C\u0430\u0433\u0430\u0437\u0438\u043D\u043E\u043C \u043F\u043E\u0434 \u043D\u0430\u0437\u0432\u0430\u043D\u0438\u0435\u043C \xAB\u0411\u044E\u0440\u043E \u043D\u0430\u0445\u043E\u0434\u043E\u043A\xBB, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043F\u0440\u043E\u0434\u0430\u0432\u0430\u043B\u0438\u0441\u044C \u0442\u043E\u0432\u0430\u0440\u044B \u043E\u0442 \u043C\u0430\u0441\u0442\u0435\u0440\u043E\u0432-\u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u0438\u043A\u043E\u0432.</p><p>\u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D \u043F\u043E\u0434\u0443\u043C\u0430\u043B, \u0447\u0442\u043E \u0442\u0430\u043A\u0438\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u043E\u0432 \u043C\u043E\u0433\u043B\u043E \u0431\u044B \u0431\u044B\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u0435, \u0435\u0441\u043B\u0438 \u0431\u044B \u0443 \u043D\u0438\u0445 \u0431\u044B\u043B\u0430 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0433\u0434\u0435-\u0442\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u0438 \u0433\u0434\u0435-\u0442\u043E \u043F\u0440\u043E\u0434\u0430\u0432\u0430\u0442\u044C \u0441\u0432\u043E\u0438 \u0438\u0437\u0434\u0435\u043B\u0438\u044F. \u0414\u0430 \u0438 \u0432\u043E\u043E\u0431\u0449\u0435, \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0436\u0438\u0442\u0435\u043B\u0435\u0439 \u0431\u043E\u043B\u044C\u0448\u043E\u0433\u043E \u0433\u043E\u0440\u043E\u0434\u0430 \u0440\u0430\u043D\u043E \u0438\u043B\u0438 \u043F\u043E\u0437\u0434\u043D\u043E \u0441\u0442\u0430\u043B\u043A\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0441 \u043E\u0434\u043D\u043E\u0439 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u043E\u0439 \u2013 \u0435\u0441\u043B\u0438 \u043D\u0443\u0436\u043D\u043E \u043E\u0442\u0440\u0435\u043C\u043E\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0438\u043B\u0438 \u0441\u043C\u0430\u0441\u0442\u0435\u0440\u0438\u0442\u044C \u0447\u0442\u043E-\u043B\u0438\u0431\u043E \u0434\u043E\u043C\u0430, \u0442\u043E \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u044D\u0442\u043E \u043A\u0440\u0430\u0439\u043D\u0435 \u0442\u0440\u0443\u0434\u043D\u043E. \u041D\u0435\u0445\u0432\u0430\u0442\u043A\u0430 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u0433\u043E \u043C\u0435\u0441\u0442\u0430, \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u0437\u043D\u0430\u043D\u0438\u0439 \u0438 \u043D\u0430\u0432\u044B\u043A\u043E\u0432, \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u044B\u0445 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 (\u0438 \u0443\u0436 \u0442\u0435\u043C \u0431\u043E\u043B\u0435\u0435 \u2013 \u0441\u0435\u0440\u044C\u0451\u0437\u043D\u043E\u0433\u043E \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F), \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0448\u0443\u043C\u0435\u0442\u044C \u0432 \u043F\u043E\u0437\u0434\u043D\u0438\u0435 \u0447\u0430\u0441\u044B \u0438 \u0442.\u0434.</p><p>\u0422\u0430\u043A \u0443 \u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D\u0430 \u0421\u043A\u0432\u043E\u0440\u0446\u043E\u0432\u0430 \u0438 \u0440\u043E\u0434\u0438\u043B\u0430\u0441\u044C \u0438\u0434\u0435\u044F \u043E\u0442\u043A\u0440\u044B\u0442\u044C \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0443\u044E, \u043A\u0443\u0434\u0430 \u0431\u044B \u043C\u043E\u0433 \u043F\u0440\u0438\u0439\u0442\u0438 \u043B\u044E\u0431\u043E\u0439 \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0439, \u0447\u0442\u043E\u0431\u044B \u043F\u0440\u043E\u0432\u0435\u0441\u0442\u0438 \u0442\u0430\u043C \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0447\u0430\u0441\u043E\u0432 \u0438 \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0447\u0442\u043E-\u043D\u0438\u0431\u0443\u0434\u044C \u0441\u0432\u043E\u0438\u043C\u0438 \u0440\u0443\u043A\u0430\u043C\u0438. \u042D\u0442\u0443 \u0438\u0434\u0435\u044E \u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D \u0432\u044B\u043D\u0430\u0448\u0438\u0432\u0430\u043B \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u043B\u0435\u0442 \u0438 \u043E\u0434\u043D\u0430\u0436\u0434\u044B \u043F\u043E\u0434\u0435\u043B\u0438\u043B\u0441\u044F \u0435\u0439 \u0441\u043E \u0441\u0432\u043E\u0438\u043C \u043E\u0434\u043D\u043E\u043A\u0430\u0448\u043D\u0438\u043A\u043E\u043C \u041E\u043B\u0435\u0433\u043E\u043C \u0424\u0430\u0440\u0430\u0434\u0436\u0443\u043B\u043B\u0430\u0435\u0432\u044B\u043C, \u043D\u0430 \u0442\u043E\u0442 \u043C\u043E\u043C\u0435\u043D\u0442 \u2013 \u0432\u043B\u0430\u0434\u0435\u043B\u044C\u0446\u0435\u043C \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u043A\u043E\u043C\u043F\u0430\u043D\u0438\u0438, \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0438\u043C\u0441\u044F \u0432 \u043F\u043E\u0438\u0441\u043A\u0435 \u043D\u043E\u0432\u043E\u0439 \u043F\u0435\u0440\u0441\u043F\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0439 \u0440\u044B\u043D\u043E\u0447\u043D\u043E\u0439 \u043D\u0438\u0448\u0438. \u041F\u0440\u043E\u043F\u0438\u0441\u0430\u0432, \u043A\u0430\u043A \u0442\u043E\u0433\u0434\u0430 \u0438\u043C \u043A\u0430\u0437\u0430\u043B\u043E\u0441\u044C, \u0432\u043F\u043E\u043B\u043D\u0435 \u0440\u0435\u0430\u043B\u0438\u0437\u0443\u0435\u043C\u044B\u0439 \u0431\u0438\u0437\u043D\u0435\u0441-\u043F\u043B\u0430\u043D, \u043E\u043D\u0438 \u0440\u0435\u0448\u0438\u043B\u0438 \u043E\u0442\u043A\u0440\u044B\u0442\u044C \u0432 \u041C\u043E\u0441\u043A\u0432\u0435 \u0442\u0430\u043A\u043E\u0435 \u0437\u0430\u0432\u0435\u0434\u0435\u043D\u0438\u0435.</p><p><img src="'+s+'" alt="" title="\u041E\u043B\u0435\u0433 \u0424\u0430\u0440\u0430\u0434\u0436\u0443\u043B\u043B\u0430\u0435\u0432 \u0438 \u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D \u0421\u043A\u0432\u043E\u0440\u0446\u043E\u0432"> <em>\u041E\u043B\u0435\u0433 \u0424\u0430\u0440\u0430\u0434\u0436\u0443\u043B\u043B\u0430\u0435\u0432 \u0438 \u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D \u0421\u043A\u0432\u043E\u0440\u0446\u043E\u0432</em></p><p>\u0412\u043E\u043F\u043B\u043E\u0449\u0430\u0442\u044C \u0438\u0434\u0435\u044E \u0432 \u0436\u0438\u0437\u043D\u044C \u043E\u043D\u0438 \u043D\u0430\u0447\u0430\u043B\u0438 \u0432 \u0441\u0435\u043D\u0442\u044F\u0431\u0440\u0435 2012 \u0433\u043E\u0434\u0430, \u0430 \u0443\u0436\u0435 \u0432 \u043E\u043A\u0442\u044F\u0431\u0440\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043B\u043E\u0441\u044C \u043E\u0442\u043A\u0440\u044B\u0442\u0438\u0435 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \xAB\u0414\u0432\u043E\u0440 \u0421\u043E\u0442\u0440\u0443\u0434\u043D\u0435\u0439\xBB, \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0438\u0432\u0448\u0435\u0439\u0441\u044F \u0432 \u0441\u0430\u043C\u043E\u043C \u0446\u0435\u043D\u0442\u0440\u0435 \u041C\u043E\u0441\u043A\u0432\u044B, \u043D\u0435\u0434\u0430\u043B\u0435\u043A\u043E \u043E\u0442 \u0427\u0438\u0441\u0442\u044B\u0445 \u041F\u0440\u0443\u0434\u043E\u0432, \u0432 \u043F\u043E\u0434\u0432\u0430\u043B\u0435 \u043E\u0434\u043D\u043E\u0433\u043E \u0438\u0437 \u0434\u0432\u043E\u0440\u0438\u043A\u043E\u0432 \u041C\u0438\u043B\u044E\u0442\u0438\u043D\u0441\u043A\u043E\u0433\u043E \u043F\u0435\u0440\u0435\u0443\u043B\u043A\u0430.</p><p>\u0421 \u0441\u0430\u043C\u043E\u0433\u043E \u043D\u0430\u0447\u0430\u043B\u0430 \u043E\u0442\u0446\u043E\u0432-\u043E\u0441\u043D\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043B\u0430 \u0433\u0440\u0443\u043F\u043F\u0430 \u0435\u0434\u0438\u043D\u043E\u043C\u044B\u0448\u043B\u0435\u043D\u043D\u0438\u043A\u043E\u0432, \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0440\u0430\u0431\u043E\u0442\u0430\u043B\u0438 \u0434\u043E\u0431\u0440\u043E\u0432\u043E\u043B\u044C\u043D\u044B\u043C\u0438 \u043F\u043E\u043C\u043E\u0449\u043D\u0438\u043A\u0430\u043C\u0438. \u041C\u043D\u043E\u0433\u0438\u0435 \u043F\u0440\u0438\u0448\u043B\u0438 \u043A\u0430\u043A \u043A\u043B\u0438\u0435\u043D\u0442\u044B, \u0447\u0442\u043E\u0431\u044B \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0447\u0442\u043E-\u0442\u043E \u0434\u043B\u044F \u0441\u0435\u0431\u044F \u0438 \u0443\u0439\u0442\u0438, \u043D\u043E \u0431\u044B\u043B\u0438 \u043D\u0430\u0441\u0442\u043E\u043B\u044C\u043A\u043E \u0437\u0430\u0445\u0432\u0430\u0447\u0435\u043D\u044B \u0438\u0434\u0435\u0435\u0439 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439, \u0447\u0442\u043E \u043E\u0441\u0442\u0430\u043B\u0438\u0441\u044C \u0432 \u043F\u0440\u043E\u0435\u043A\u0442\u0435, \u0430 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0434\u0430\u0436\u0435 \u0441\u043C\u0435\u043D\u0438\u043B\u0438 \u0434\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u0440\u043E\u0434 \u0441\u0432\u043E\u0435\u0439 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438.</p><p>\u041F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u0435 \u0432\xA0\u043E\u0433\u0440\u043E\u043C\u043D\u043E\u043C \u0434\u043B\u044F \u043D\u0430\u0441 \u043F\u043E \u0442\u0435\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0430\u043C \u043F\u043E\u0434\u0432\u0430\u043B\u0435 \u043D\u0430\xA0200\xA0\u043C\u0435\u0442\u0440\u043E\u0432 \u043E\u043A\u0430\u0437\u0430\u043B\u043E\u0441\u044C \u0431\u044B\u0432\u0448\u0435\u0439 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u043E\u0439, \u0430 \u0442\u043E\u0447\u043D\u0435\u0435 \u2013 \u0447\u0430\u0441\u0442\u044C\u044E \u0440\u0435\u0441\u0442\u0430\u0432\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439. \u041E\u0442 \u043D\u0435\u0451 \u043C\u044B \u0443\u043D\u0430\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043B\u0438 \u043A\u043E\u0435-\u043A\u0430\u043A\u043E\u0435 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0442\u043E\u0433\u0434\u0430 \u0434\u043B\u044F \u043D\u0430\u0441 \u0431\u044B\u043B\u043E \u043A\u0440\u0430\u0439\u043D\u0435 \u0446\u0435\u043D\u043D\u044B\u043C. \u041C\u044B \u0441\u043D\u044F\u043B\u0438 \u043A\u043E\u043C\u043D\u0430\u0442\u0443 \u0432 30 \u043C\u0435\u0442\u0440\u043E\u0432 \u0438\xA0\u043D\u0430\u0447\u0430\u043B\u0438 \u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C. \u041C\u0435\u043D\u044C\u0448\u0435, \u0447\u0435\u043C \u0447\u0435\u0440\u0435\u0437 \u043F\u043E\u043B\u0433\u043E\u0434\u0430, \u043C\u044B \u0442\u0430\u043C \u0437\u0430\u043D\u0438\u043C\u0430\u043B\u0438 \u0443\u0436\u0435 90\xA0\u043C\u0435\u0442\u0440\u043E\u0432.</p><p>\u0418\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E \u0432 \u043F\u0440\u043E\u0435\u043A\u0442 \u0431\u044B\u043B\u043E \u0432\u043B\u043E\u0436\u0435\u043D\u043E \u043E\u043A\u043E\u043B\u043E 500\xA0000 \u0440\u0443\u0431\u043B\u0435\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0431\u044B\u043B\u0438 \u0432\u0437\u044F\u0442\u044B \u0438\u0437 \u043B\u0438\u0447\u043D\u044B\u0445 \u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u0438\u0439 \u041E\u043B\u0435\u0433\u0430 \u0438 \u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D\u0430. \u041F\u043E\u043B\u043E\u0432\u0438\u043D\u0430 \u044D\u0442\u0438\u0445 \u0434\u0435\u043D\u0435\u0433 \u0431\u044B\u043B\u0430 \u043F\u043E\u0442\u0440\u0430\u0447\u0435\u043D\u0430 \u043D\u0430 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u043E\u0435 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435, \u0434\u0440\u0443\u0433\u0430\u044F \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u0430 \u2013 \u043D\u0430 \u0430\u0440\u0435\u043D\u0434\u0443 \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u044F \u0432 \u043F\u0435\u0440\u0432\u044B\u0435 \u043C\u0435\u0441\u044F\u0446\u044B \u0440\u0430\u0431\u043E\u0442\u044B. \u0427\u0435\u0440\u0435\u0437 3 \u043C\u0435\u0441\u044F\u0446\u0430 \u043F\u043E\u0441\u043B\u0435 \u043E\u0442\u043A\u0440\u044B\u0442\u0438\u044F \u043C\u044B \u0441\u043C\u043E\u0433\u043B\u0438 \u0432\u044B\u0439\u0442\u0438 \u043D\u0430 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0439 \u043D\u043E\u043B\u044C, \u0438 \u0434\u0430\u043B\u044C\u043D\u0435\u0439\u0448\u0435\u0435 \u0438\u043D\u0432\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u043B\u043E\u0441\u044C \u0443\u0436\u0435 \u0438\u0437 \u043F\u043E\u0441\u0442\u0443\u043F\u0430\u044E\u0449\u0435\u0439 \u043F\u0440\u0438\u0431\u044B\u043B\u0438.</p><p><strong>\u0428\u0443\u043C\u0435\u0442\u044C \u0438 \u043F\u044B\u043B\u0438\u0442\u044C \u2013 \u0431\u0435\u0437 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0439!</strong></p><p>\u0418\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E \u0432 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u043C\u043E\u0436\u043D\u043E \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442\u044C \u043B\u0438\u0448\u044C \u043F\u0440\u043E\u0441\u0442\u0435\u0439\u0448\u0438\u0435 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u0435 \u0440\u0430\u0431\u043E\u0442\u044B. \u0413\u043B\u0430\u0432\u043D\u044B\u043C \u0441\u0442\u0430\u043D\u043A\u043E\u043C \u0431\u044B\u043B\u0430 \u0441\u0442\u0430\u0446\u0438\u043E\u043D\u0430\u0440\u043D\u0430\u044F \u0446\u0438\u0440\u043A\u0443\u043B\u044F\u0440\u043D\u0430\u044F \u043F\u0438\u043B\u0430 \u0441 \u0441\u0430\u043C\u043E\u0434\u0435\u043B\u044C\u043D\u044B\u043C\u0438 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u044E\u0449\u0438\u043C\u0438 \u0438 \u0441\u044A\u0451\u043C\u043D\u043E\u0439 \u043A\u0430\u0440\u0435\u0442\u043A\u043E\u0439. \u041A\u043E\u0433\u0434\u0430 \u043A\u0430\u0440\u0435\u0442\u043A\u0430 \u0443\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u043B\u0430\u0441\u044C, \u0447\u0442\u043E\u0431\u044B \u0440\u0430\u0441\u043F\u0438\u043B\u0438\u0442\u044C, \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u043B\u0438\u0441\u0442 \u0444\u0430\u043D\u0435\u0440\u044B, \u0432\u0441\u0435 \u0434\u0440\u0443\u0433\u0438\u0435 \u0440\u0430\u0431\u043E\u0442\u044B \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u043B\u043E\u0441\u044C \u043E\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u0442\u044C, \u0430 \u0441 \u0432\u0435\u0440\u0441\u0442\u0430\u043A\u043E\u0432 \u0432\u0441\u0451 \u0443\u0431\u0438\u0440\u0430\u0442\u044C \u043D\u0430 \u043F\u043E\u043B \u2013 \u043C\u0435\u0441\u0442\u0430 \u043D\u0435 \u0445\u0432\u0430\u0442\u0430\u043B\u043E.</p><p>\u0422\u0430\u043A\u0436\u0435 \u0443 \u043D\u0430\u0441 \u0438\u043C\u0435\u043B\u0438\u0441\u044C \u0442\u043E\u0440\u0446\u043E\u0432\u043E\u0447\u043D\u0430\u044F \u043F\u0438\u043B\u0430, \u0441\u0432\u0435\u0440\u043B\u0438\u043B\u044C\u043D\u044B\u0439 \u0441\u0442\u0430\u043D\u043E\u043A, \u043B\u0435\u043D\u0442\u043E\u0447\u043D\u043E-\u043F\u0438\u043B\u044C\u043D\u044B\u0439 \u0441\u0442\u0430\u043D\u043E\u043A \u0438 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u0440\u0435\u0439\u0441\u043C\u0443\u0441. \u041D\u0443 \u0438, \u0440\u0430\u0437\u0443\u043C\u0435\u0435\u0442\u0441\u044F, \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u043A\u043E\u043C\u043F\u043B\u0435\u043A\u0442\u043E\u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u0433\u043E \u043C\u0435\u0445\u0430\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0438 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430. \u0414\u043B\u044F \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430, \u0432\u043F\u0435\u0440\u0432\u044B\u0435 \u043F\u043E\u043F\u0430\u0432\u0448\u0435\u0433\u043E \u0432 \u0441\u0442\u043E\u043B\u044F\u0440\u043A\u0443, \u0431\u043E\u043B\u0435\u0435 \u0447\u0435\u043C \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E. \u0421\u0430\u043C\u043E\u0435 \u0433\u043B\u0430\u0432\u043D\u043E\u0435 \u2013 \u043C\u043E\u0436\u043D\u043E \u0431\u044B\u043B\u043E \u0448\u0443\u043C\u0435\u0442\u044C \u0438 \u043F\u044B\u043B\u0438\u0442\u044C \u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0434\u0443\u0448\u0435 \u0443\u0433\u043E\u0434\u043D\u043E!</p><p><img src="'+o+'" alt="" title="\u0414\u0430\u0440 \u0442\u0440\u0443\u0434\u0430"></p><p>\u0423\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u0442\u044C \u0447\u0442\u043E-\u0442\u043E \u043D\u043E\u0432\u043E\u0435 \u0431\u044B\u043B\u043E \u0443\u0436\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u043D\u0435\u0433\u0434\u0435, \u043F\u043E\u044D\u0442\u043E\u043C\u0443, \u043C\u043E\u0436\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u0442\u044C, \u0447\u0442\u043E \u0432 \u043F\u0435\u0440\u0432\u044B\u0435 \u0434\u0432\u0430 \u0433\u043E\u0434\u0430 - \u0434\u043E \u043F\u0435\u0440\u0435\u0435\u0437\u0434\u0430 - \u043C\u044B \u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u043C \u043E\u0442\u043B\u0430\u0436\u0438\u0432\u0430\u043B\u0438 \u043C\u0435\u0445\u0430\u043D\u0438\u0437\u043C \u0440\u0430\u0431\u043E\u0442\u044B \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439. \u041F\u0440\u0438\u0448\u043B\u043E\u0441\u044C \u043F\u0435\u0440\u0435\u043E\u0441\u043C\u044B\u0441\u043B\u0438\u0442\u044C \u043C\u043D\u043E\u0433\u0438\u0435 \u043C\u043E\u043C\u0435\u043D\u0442\u044B \u0438 \u043E\u0442\u043A\u0430\u0437\u0430\u0442\u044C\u0441\u044F \u043E\u0442 \u043C\u043D\u043E\u0433\u0438\u0445 \u0438\u0434\u0435\u0439, \u043A\u0430\u0437\u0430\u0432\u0448\u0438\u0445\u0441\u044F \u0432\u043D\u0430\u0447\u0430\u043B\u0435 \u043D\u0435\u0437\u044B\u0431\u043B\u0435\u043C\u044B\u043C\u0438.</p><p>\u041C\u044B \u043F\u043E\u043D\u044F\u043B\u0438, \u043A\u0430\u043A \u043D\u0443\u0436\u043D\u043E \u0432\u044B\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0442\u044C \u0440\u0430\u0431\u043E\u0442\u0443 \u0441 \u043A\u043B\u0438\u0435\u043D\u0442\u0430\u043C\u0438, \u043A\u0430\u043A\u0438\u043C \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0430\u0434\u043C\u0438\u043D\u0438\u0441\u0442\u0440\u0430\u0442\u043E\u0440 \u0438 \u0447\u0442\u043E \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u0434\u0435\u043B\u0430\u0442\u044C, \u043A\u0430\u043A \u043B\u0443\u0447\u0448\u0435 \u043E\u0431\u0443\u0441\u0442\u0440\u043E\u0438\u0442\u044C \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0443\u044E, \u043A\u0430\u043A\u0438\u0435 \u0434\u043E\u043B\u0436\u043D\u044B \u0431\u044B\u0442\u044C \u0442\u0430\u0440\u0438\u0444\u044B \u0438 \u043A\u0430\u043A\u0438\u0445 \u0443\u0441\u043B\u0443\u0433 \u043E\u0436\u0438\u0434\u0430\u044E\u0442\xA0 \u043E\u0442 \u043D\u0430\u0441 \u0432 \u043F\u0435\u0440\u0432\u0443\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C. \u0412\u0441\u0451 \u044D\u0442\u043E \u2013 \u043E\u0447\u0435\u043D\u044C \u0432\u0430\u0436\u043D\u044B\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B, \u0438 \u0442\u043E, \u0447\u0442\u043E \u043D\u0430\u0448\u0430 \xAB\u043E\u0431\u043A\u0430\u0442\u043A\u0430\xBB \u043F\u0440\u043E\u0438\u0437\u043E\u0448\u043B\u0430 \u0432 \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0441\u0436\u0430\u0442\u043E\u0439 (\u043F\u043E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0443) \u0444\u043E\u0440\u043C\u0435, \u0441\u0442\u0430\u043B\u043E \u043D\u0435\u0432\u0435\u0440\u043E\u044F\u0442\u043D\u044B\u043C \u0431\u043B\u0430\u0433\u043E\u043C \u0434\u043B\u044F \u043D\u0430\u0441 \u2013 \u043D\u0430\u0447\u0438\u043D\u0430\u0439 \u043C\u044B \u0441\u0440\u0430\u0437\u0443 \u043D\u0430 \u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u043F\u043B\u043E\u0449\u0430\u0434\u043A\u0435, \u0432\u0441\u0451 \u044D\u0442\u043E \u043F\u043E\u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043B\u043E \u0431\u044B \u043A\u043E\u043B\u043E\u0441\u0441\u0430\u043B\u044C\u043D\u044B\u0445, \u043F\u0440\u043E\u0441\u0442\u043E \u043D\u0435\u043F\u043E\u0434\u044A\u0451\u043C\u043D\u044B\u0445 \u0441\u0440\u0435\u0434\u0441\u0442\u0432 \u0438 \u0443\u0441\u0438\u043B\u0438\u0439.</p><p><strong>\u0421\u043E\u0431\u0438\u0440\u0430\u0435\u043C \u0447\u0435\u043C\u043E\u0434\u0430\u043D\u044B</strong></p><p>\u0412\u0441\u043A\u043E\u0440\u0435 \u043D\u0435\u043E\u0442\u0432\u0440\u0430\u0442\u0438\u043C\u043E\u0441\u0442\u044C \u043F\u0435\u0440\u0435\u0435\u0437\u0434\u0430 \u0441\u0442\u0430\u043B\u0430 \u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E\u0439. \u041A\u043E\u0433\u0434\u0430 \u0432 \u043A\u0430\u043A\u043E\u0439-\u0442\u043E \u043C\u043E\u043C\u0435\u043D\u0442 \u0432 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u043F\u0440\u043E\u0441\u0442\u043E \xAB\u0437\u0430\u0441\u0442\u0440\u044F\u043B\u043E\xBB \u0442\u0440\u0438 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043A\u0440\u0443\u043F\u043D\u044B\u0445 (\u0434\u043B\u044F \u0442\u043E\u0433\u043E \u043D\u0430\u0448\u0435\u0433\u043E \u0443\u0440\u043E\u0432\u043D\u044F) \u043F\u0440\u043E\u0435\u043A\u0442\u0430, \u043D\u0430\u0434 \u043A\u043E\u0442\u043E\u0440\u044B\u043C\u0438 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u0431\u044B\u043B\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E, \u0441\u0442\u0430\u043B\u043E \u044F\u0441\u043D\u043E, \u0447\u0442\u043E \xAB\u0442\u0430\u043A \u0436\u0438\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435\u043B\u044C\u0437\u044F\xBB. \u041C\u0430\u0441\u0442\u0435\u0440\u0430\u043C \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u043B\u043E\u0441\u044C \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u0438\u0437\u0432\u0438\u0432\u0430\u0442\u044C\u0441\u044F \u043C\u0435\u0436\u0434\u0443 \u0447\u0443\u0436\u0438\u043C\u0438 \u0434\u0435\u0442\u0430\u043B\u044F\u043C\u0438, \u0430 \u0434\u0435\u043B\u0430\u0442\u044C \u0447\u0442\u043E-\u043B\u0438\u0431\u043E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0431\u044B\u043B\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u043F\u043E \u043E\u0447\u0435\u0440\u0435\u0434\u0438. \u0415\u0441\u043B\u0438 \u0436\u0435 \u0447\u0442\u043E-\u0442\u043E \u043D\u0443\u0436\u043D\u043E \u0431\u044B\u043B\u043E \u0432\u044B\u043D\u0435\u0441\u0442\u0438, \u044D\u0442\u043E \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u043B\u043E\u0441\u044C \u0432 \u0441\u043B\u043E\u0436\u043D\u0443\u044E \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u044E.</p><p>\u041D\u0435 \u043F\u0440\u0438\u0431\u0430\u0432\u043B\u044F\u043B\u0430 \u0443\u0434\u043E\u0431\u0441\u0442\u0432\u0430 \u0438 \u043A\u0440\u0443\u0442\u0430\u044F \u0443\u0437\u043A\u0430\u044F \u043B\u0435\u0441\u0442\u043D\u0438\u0446\u0430, \u0432\u0435\u0434\u0443\u0449\u0430\u044F \u0432 \u043D\u0430\u0448 \u043F\u043E\u0434\u0432\u0430\u043B\u044C\u0447\u0438\u043A. \u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u0444\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u043E\u0432\u0430\u043B\u0430 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u0430\u044F \u043F\u043E\u043A\u0440\u0430\u0441\u043E\u0447\u043D\u0430\u044F \u043A\u043E\u043C\u043D\u0430\u0442\u0430 (\u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0441\u043E\u0432\u043C\u0435\u0449\u0430\u0432\u0448\u0430\u044F \u0432 \u0441\u0435\u0431\u0435 \u0440\u0430\u0437\u043D\u044B\u0435 \u0434\u0440\u0443\u0433\u0438\u0435 \u0444\u0443\u043D\u043A\u0446\u0438\u0438), \u0430 \u0441\u043E\u0441\u0435\u0434\u043D\u044F\u044F \u043A\u0435\u0440\u0430\u043C\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u0432\u0441\u0451 \u0447\u0430\u0449\u0435 \u0432\u044B\u0440\u0430\u0436\u0430\u043B\u0430 \u043D\u0435\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u043E \u043F\u043E \u043F\u043E\u0432\u043E\u0434\u0443 \u0448\u0443\u043C\u0430 \u0438 \u043F\u044B\u043B\u0438. \u041F\u0440\u0435\u0434\u0435\u043B \u0442\u0435\u0440\u043F\u0435\u043D\u0438\u044F \u0431\u044B\u043B \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442 \u0438, \u043F\u043E\u0441\u043C\u043E\u0442\u0440\u0435\u0432 \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0435 \u043E\u0434\u043D\u043E\u0439 \u043D\u0435\u0434\u0435\u043B\u0438 \u0434\u0432\u0430-\u0442\u0440\u0438 \u043C\u0435\u0441\u0442\u0430, \u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D \u043F\u0440\u0438\u043D\u044F\u043B \u0432\u043E\u043B\u0435\u0432\u043E\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u0435: \u043F\u0435\u0440\u0435\u0435\u0437\u0436\u0430\u0435\u043C!</p><p>\u041F\u0435\u0440\u0435\u0435\u0445\u0430\u0432 \u0432 \u0434\u0435\u043A\u0430\u0431\u0440\u0435 2014-\u0433\u043E \u0438\u0437 \u0442\u0435\u0441\u043D\u043E\u0433\u043E \u043F\u043E\u0434\u0432\u0430\u043B\u0430 \u0432 \u0446\u0435\u0445\u0430 \u041D\u0418\u0418\u0414\u0410\u0420\u0430 \u043D\u0430 \u041F\u0440\u0435\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u043A\u0435, \u043C\u044B \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u043B\u0438 \u043E\u0431\u0449\u0443\u044E \u043F\u043B\u043E\u0449\u0430\u0434\u044C \u0432 3,5 \u0440\u0430\u0437\u0430 - \u0434\u043E 320 \xAB\u043A\u0432\u0430\u0434\u0440\u0430\u0442\u043E\u0432\xBB. \u0421 \u044F\u043D\u0432\u0430\u0440\u044F 2016-\u0433\u043E \u043D\u0430\u0448\u0430 \u043F\u043B\u043E\u0449\u0430\u0434\u044C \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u043B\u0430 \u0443\u0436\u0435 760 \xAB\u043A\u0432\u0430\u0434\u0440\u0430\u0442\u043E\u0432\xBB, \u0430 \u0441\u0435\u0439\u0447\u0430\u0441, \u0432 2017-\u043C, \u043C\u044B \u0432 \u0446\u0435\u043B\u043E\u043C \u0437\u0430\u043D\u0438\u043C\u0430\u0435\u043C \u043E\u043A\u043E\u043B\u043E 1000 \u043A\u0432\u0430\u0434\u0440\u0430\u0442\u043D\u044B\u0445 \u043C\u0435\u0442\u0440\u043E\u0432.</p><p><img src="'+i+'" alt="" title="\u0414\u0430\u0440 \u0442\u0440\u0443\u0434\u0430"></p><p>\u0412 \u0442\u0435\u0447\u0435\u043D\u0438\u0435 2015 \u0433\u043E\u0434\u0430 \u043C\u044B, \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u043D\u0435 \u043E\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u044F \u0440\u0430\u0431\u043E\u0442\u0443 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430, \u043E\u0431\u0443\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u043B\u0438\u0441\u044C \u043D\u0430 \u043D\u043E\u0432\u043E\u043C \u043C\u0435\u0441\u0442\u0435, \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u0434\u043E\u0437\u0430\u043A\u0443\u043F\u0430\u043B\u0438 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u0438 \u043E\u0433\u043B\u044F\u0434\u044B\u0432\u0430\u043B\u0438\u0441\u044C \u043F\u043E \u0441\u0442\u043E\u0440\u043E\u043D\u0430\u043C \u0432 \u043F\u043E\u0438\u0441\u043A\u0430\u0445 \u043D\u043E\u0432\u044B\u0445 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0435\u0439. \u041F\u0435\u0440\u0432\u044B\u043C \u0434\u0435\u043B\u043E\u043C \u0431\u044B\u043B \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0451\u043D \u0444\u043E\u0440\u043C\u0430\u0442\u043D\u043E-\u0440\u0430\u0441\u043A\u0440\u043E\u0435\u0447\u043D\u044B\u0439 \u0441\u0442\u0430\u043D\u043E\u043A \u0441\u0440\u0435\u0434\u043D\u0435\u0433\u043E \u0440\u0430\u0437\u043C\u0435\u0440\u0430. \u0414\u0430\u043B\u0435\u0435 \u043F\u043B\u0430\u043D\u043E\u043C\u0435\u0440\u043D\u043E \u043F\u043E\u043A\u0443\u043F\u0430\u043B\u0438\u0441\u044C \u0434\u0440\u0443\u0433\u0438\u0435 \u043F\u0438\u043B\u044B, \u0440\u0435\u0439\u0441\u043C\u0443\u0441\u044B, \u0444\u0443\u0433\u0430\u043D\u043A\u0438 \u0438 \u043F\u0440\u043E\u0447\u0438\u0435 \u0441\u0442\u0430\u043D\u043A\u0438.</p><p>\u0412 \u044F\u043D\u0432\u0430\u0440\u0435 2016 \u0433\u043E\u0434\u0430 \u043C\u044B \u043F\u043E\u043B\u0443\u0447\u0438\u043B\u0438 \u0441\u0443\u0431\u0441\u0438\u0434\u0438\u044E \u043F\u043E \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u0435 \u0426\u041C\u0418\u0422 - \u0426\u0435\u043D\u0442\u0440\u0430 \u043C\u043E\u043B\u043E\u0434\u0451\u0436\u043D\u043E\u0433\u043E \u0438\u043D\u043D\u043E\u0432\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0433\u043E \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0430. \u042D\u0442\u043E \u043F\u043E\u0437\u0432\u043E\u043B\u0438\u043B\u043E \u043D\u0430\u043C \u0440\u0430\u0441\u0448\u0438\u0440\u0438\u0442\u044C \u0441\u0432\u043E\u0438 \u043F\u043B\u043E\u0449\u0430\u0434\u043A\u0438 \u0438 \u0437\u0430\u043A\u0443\u043F\u0438\u0442\u044C \u0441\u0435\u0440\u044C\u0451\u0437\u043D\u043E\u0435 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u2013 \u043D\u043E\u0432\u044B\u0435 \u043B\u0430\u0437\u0435\u0440\u043D\u044B\u0435 \u0438 \u0427\u041F\u0423-\u0444\u0440\u0435\u0437\u0435\u0440\u043D\u044B\u0435 \u0441\u0442\u0430\u043D\u043A\u0438, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0440\u044F\u0434 \u043D\u0435\u0434\u043E\u0441\u0442\u0443\u043F\u043D\u043E\u0433\u043E \u043D\u0430\u043C \u0440\u0430\u043D\u0435\u0435 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u043E\u0433\u043E \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u0441\u0442\u0430\u043D\u043A\u0438 \u0434\u043B\u044F \u0440\u0430\u0431\u043E\u0442\u044B \u0441 \u043C\u0435\u0442\u0430\u043B\u043B\u043E\u043C. \u0422\u0430\u043A\u0436\u0435 \u043F\u043E \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044E \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u044B \u0426\u041C\u0418\u0422 \u043C\u044B \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u043B\u0438 \u043D\u0435\u043F\u0440\u043E\u0444\u0438\u043B\u044C\u043D\u043E\u0435 \u0434\u043B\u044F \u0441\u0435\u0431\u044F \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u2013 3D-\u0441\u043A\u0430\u043D\u0435\u0440 \u0438 3D-\u043F\u0440\u0438\u043D\u0442\u0435\u0440, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u0435\u0434\u043D\u0430\u0437\u043D\u0430\u0447\u0435\u043D\u044B \u0434\u043B\u044F \u043F\u0440\u043E\u0442\u043E\u0442\u0438\u043F\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u043D\u0435\u043A\u0440\u0443\u043F\u043D\u044B\u0445 \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u043E\u0432. \u0412\u0430\u0436\u043D\u044B\u043C \u044D\u0442\u0430\u043F\u043E\u043C \u0441\u0442\u0430\u043B\u0430 \u043D\u0430\u0434\u0441\u0442\u0440\u043E\u0439\u043A\u0430 \u043B\u0451\u0433\u043A\u043E\u0433\u043E \u0432\u0442\u043E\u0440\u043E\u0433\u043E \u044D\u0442\u0430\u0436\u0430 \u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u043C \u0446\u0435\u0445\u0435 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430. \u042D\u0442\u043E \u043F\u043E\u0437\u0432\u043E\u043B\u0438\u043B\u043E \u043E\u043F\u0442\u0438\u043C\u0430\u043B\u044C\u043D\u043E \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0438\u0442\u044C \u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0435 \u0437\u043E\u043D\u044B \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439.</p><p>\u0412 \u043A\u043E\u043D\u0446\u0435 2016 \u0433\u043E\u0434\u0430 \u043C\u044B \u0435\u0449\u0451 \u043D\u0435\u043C\u043D\u043E\u0433\u043E \u0440\u0430\u0441\u0448\u0438\u0440\u0438\u043B\u0438\u0441\u044C \u2013 \u0430\u0440\u0435\u043D\u0434\u043E\u0432\u0430\u043B\u0438 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0435 \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u0435 \u0434\u043B\u044F \u043D\u0430\u0448\u0435\u0433\u043E \u0443\u0447\u0435\u0431\u043D\u043E\u0433\u043E \u0446\u0435\u043D\u0442\u0440\u0430, \u0437\u0430\u043D\u044F\u0442\u0438\u044F \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u0440\u0430\u043D\u044C\u0448\u0435 \u043F\u0440\u043E\u0432\u043E\u0434\u0438\u043B\u0438\u0441\u044C \u0438\u0441\u043A\u043B\u044E\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043D\u0430 \u0442\u0435\u0440\u0440\u0438\u0442\u043E\u0440\u0438\u0438 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430. \u0422\u0435\u043F\u0435\u0440\u044C \u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u043C\u043E\u0436\u0435\u0442 \u0432\u0435\u0441\u0442\u0438\u0441\u044C \u0438 \u043E\u0431\u043E\u0441\u043E\u0431\u043B\u0435\u043D\u043D\u043E.</p><p><strong>\u041A\u0442\u043E \u0438 \u0437\u0430\u0447\u0435\u043C \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u0432 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0443\u044E</strong></p><p>\u0423 \u043D\u0430\u0441 \u043C\u043E\u0433\u0443\u0442 \u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u0438 \u043E\u043F\u044B\u0442\u043D\u044B\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0430, \u0438 \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0449\u0438\u0435. \u041D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0441\u0435\u0439\u0447\u0430\u0441 \u0447\u0435\u043B\u043E\u0432\u0435\u043A, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0445\u043E\u0447\u0435\u0442 \u043D\u0430\u0443\u0447\u0438\u0442\u044C\u0441\u044F \u0447\u0442\u043E-\u0442\u043E \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0441\u0432\u043E\u0438\u043C\u0438 \u0440\u0443\u043A\u0430\u043C\u0438 \u0432 \u0441\u0432\u043E\u0439 \u0437\u0430\u043A\u043E\u043D\u043D\u044B\u0439 \u0432\u044B\u0445\u043E\u0434\u043D\u043E\u0439, \u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0438\u0439\u0442\u0438 \u043A \u043D\u0430\u043C \u043D\u0430 \u0437\u0430\u043D\u044F\u0442\u0438\u044F \u043F\u043E \xAB\u0441\u0442\u043E\u043B\u044F\u0440\u043A\u0435\xBB \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0443\u0440\u043E\u0432\u043D\u044F, \u043C\u044B \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C \u044D\u0442\u043E \xAB\u041F\u0443\u0442\u044C \u043C\u0430\u0441\u0442\u0435\u0440\u0430\xBB. \u041E\u0434\u043D\u0438 \u0434\u0435\u043B\u0430\u044E\u0442 \u043A\u0430\u043A\u0443\u044E-\u043D\u0438\u0431\u0443\u0434\u044C \u0432\u0435\u0449\u0438\u0446\u0443 \u0438 \u0438\u0441\u0447\u0435\u0437\u0430\u044E\u0442 \u043D\u0430\u0432\u0441\u0435\u0433\u0434\u0430. \u0410 \u043A\u0442\u043E-\u0442\u043E \u0432\u043E\u0437\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043D\u0430\u0448\u0438\u043C \u043A\u043E\u0432\u043E\u0440\u043A\u0435\u0440\u043E\u043C.</p><p>\u0411\u043E\u043B\u0435\u0435 \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u044B\u0439 \u0432\u0430\u0440\u0438\u0430\u043D\u0442 \u2013 \u043A\u043E\u0433\u0434\u0430 \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u0447\u0435\u043B\u043E\u0432\u0435\u043A, \u0443 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u0435\u0441\u0442\u044C \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u0430\u044F \u0438\u0434\u0435\u044F, \u043D\u043E \u043D\u0435\u0442 \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F, \u043A\u0430\u043A \u0435\u0451 \u043C\u043E\u0436\u043D\u043E \u0440\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u0442\u044C. \u041C\u044B \u043F\u043E\u043C\u043E\u0433\u0430\u0435\u043C \u0435\u043C\u0443 \u0432 \u044D\u0442\u043E\u043C, \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442 \u0442\u043E\u0436\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0440\u0430\u0437\u043D\u044B\u043C.</p><p>\u041F\u0440\u0438\u0445\u043E\u0434\u044F\u0442 \u043B\u044E\u0434\u0438 \u0438 \u0441 \u043A\u0430\u043A\u0438\u043C-\u0442\u043E \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u043C \u043E\u043F\u044B\u0442\u043E\u043C, \u043B\u0438\u0431\u043E \u0442\u0435\u043E\u0440\u0435\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0437\u043D\u0430\u043D\u0438\u044F\u043C\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u043C \u043D\u0443\u0436\u043D\u043E \u0438\u0437\u0433\u043E\u0442\u043E\u0432\u0438\u0442\u044C \u0447\u0442\u043E-\u0442\u043E, \u043D\u043E \u043D\u0435\u0433\u0434\u0435 \u0438 \u043D\u0435 \u043D\u0430 \u0447\u0435\u043C. \u041E\u043D\u0438 \u043C\u043E\u0433\u0443\u0442 \u0441\u0440\u0430\u0437\u0443 \u0441\u0442\u0430\u0442\u044C \u043A\u043B\u0438\u0435\u043D\u0442\u0430\u043C\u0438 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430, \u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0434\u043E\u0443\u0447\u0438\u0432\u0430\u044F\u0441\u044C \u0442\u0435\u043C \u0438\u043B\u0438 \u0438\u043D\u044B\u043C \u0432\u0435\u0449\u0430\u043C, \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440 \u2013 \u0440\u0430\u0431\u043E\u0442\u0435 \u043D\u0430 \u0441\u0442\u0430\u043D\u043A\u0430\u0445.</p><p><img src="'+n+'" alt="" title="\u0414\u0430\u0440 \u0442\u0440\u0443\u0434\u0430"></p><p>\u0415\u0449\u0451 \u043E\u0434\u0438\u043D \u0442\u0438\u043F \u043A\u043B\u0438\u0435\u043D\u0442\u043E\u0432 \u2013 \u043E\u043F\u044B\u0442\u043D\u044B\u0435 \u0441\u0442\u043E\u043B\u044F\u0440\u044B, \u0443 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0435\u0441\u0442\u044C \u0441\u0432\u043E\u0438 \u0437\u0430\u043A\u0430\u0437\u044B \u0438 \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0438\u0449\u0443\u0442 \u0434\u043B\u044F \u0441\u0435\u0431\u044F \u0431\u043E\u043B\u0435\u0435 \u0443\u0434\u043E\u0431\u043D\u043E\u0435 \u043C\u0435\u0441\u0442\u043E \u0440\u0430\u0431\u043E\u0442\u044B. \u0421\u0443\u0434\u044F \u043F\u043E \u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0445 \u0440\u0435\u0437\u0438\u0434\u0435\u043D\u0442\u043E\u0432 \u0443 \u043D\u0430\u0441 \u043D\u0435 \u0443\u043C\u0435\u043D\u044C\u0448\u0430\u0435\u0442\u0441\u044F, \u043C\u044B \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u0435\u043C \u0438\u043C \u0432\u0435\u0441\u044C\u043C\u0430 \u0432\u044B\u0433\u043E\u0434\u043D\u044B\u0435 \u0443\u0441\u043B\u043E\u0432\u0438\u044F.</p><p>\u0422\u0430\u043A\u0436\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0438 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442 (\u0437\u0430\u0447\u0430\u0441\u0442\u0443\u044E \u2013 \u0441\u0438\u043B\u0430\u043C\u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u043E\u0432-\u0440\u0435\u0437\u0438\u0434\u0435\u043D\u0442\u043E\u0432) \u0441\u0430\u043C\u044B\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u0435 \u0438 \u043E\u043A\u043E\u043B\u043E\u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u0435 \u0437\u0430\u043A\u0430\u0437\u044B. \u042D\u0442\u043E \u0442\u0435\u043C\u0430 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0445 \u0441\u0438\u043C\u0431\u0438\u043E\u0437\u043E\u0432 \u0441\u043E\u0442\u0440\u0443\u0434\u043D\u0438\u0447\u0435\u0441\u0442\u0432\u0430 \u0438 \u0441\u043A\u0440\u0435\u0449\u0438\u0432\u0430\u043D\u0438\u044F \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u0439, \u043D\u0430\u0432\u044B\u043A\u043E\u0432 \u0438 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0445 \u043F\u043E\u0440\u044B\u0432\u043E\u0432.</p><p>\u0410\u0440\u0435\u043D\u0434\u0430 \u0440\u0430\u0431\u043E\u0447\u0435\u0433\u043E \u043C\u0435\u0441\u0442\u0430 \u0432 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \xAB\u0414\u0430\u0440\xA0\u0442\u0440\u0443\u0434\u0430\xBB \u043D\u0430 \u0447\u0430\u0441 \u0441\u0442\u043E\u0438\u0442 300 \u0440\u0443\u0431\u043B\u0435\u0439, \u043D\u0430 \u0434\u0435\u043D\u044C \u2013 1300 \u0440\u0443\u0431\u043B\u0435\u0439, \u043D\u0430 \u043C\u0435\u0441\u044F\u0446 - 8000 \u0440\u0443\u0431\u043B\u0435\u0439</p><p>\u0421\u0430\u043C\u044B\u0439 \u043F\u043E\u043F\u0443\u043B\u044F\u0440\u043D\u044B\u0439 \u0442\u0430\u0440\u0438\u0444 - \u043C\u0435\u0441\u044F\u0447\u043D\u044B\u0439 \u0430\u0431\u043E\u043D\u0435\u043C\u0435\u043D\u0442. \u0422\u043E \u0435\u0441\u0442\u044C, \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442, \u043F\u043B\u0430\u0442\u0438\u0442 8000 \u0440\u0443\u0431\u043B\u0435\u0439 \u0438 \u043C\u0435\u0441\u044F\u0446 \u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0443\u0441\u043B\u0443\u0433\u0430\u043C\u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u0431\u0435\u0437 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F \u043F\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438. \u0415\u0441\u0442\u044C \u0438 \u043C\u0435\u0441\u044F\u0447\u043D\u044B\u0435 \u0442\u0430\u0440\u0438\u0444\u044B \u0434\u043B\u044F \u043F\u0440\u043E\u0444\u0435\u0441\u0441\u0438\u043E\u043D\u0430\u043B\u043E\u0432: \xAB\u041C\u0430\u0441\u0442\u0435\u0440\xBB - 17\xA0000 \u0440\u0443\u0431\u043B\u0435\u0439 (\u0441 \u0434\u043E\u0441\u0442\u0443\u043F\u043E\u043C \u0432 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0443\u044E \u0434\u043E \u0434\u0432\u0443\u0445 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0438 \u043F\u0435\u0440\u0441\u043E\u043D\u0430\u043B\u044C\u043D\u043E\u0439 \u044F\u0447\u0435\u0439\u043A\u043E\u0439 \u0432 7 \xAB\u043A\u0432\u0430\u0434\u0440\u0430\u0442\u043E\u0432\xBB) \u0438 \xAB\u041F\u0440\u043E\u0444\u0438\xBB (3 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u0438 \u044F\u0447\u0435\u0439\u043A\u0430 \u043D\u0430 12 \u043A\u0432\u0430\u0434\u0440\u0430\u0442\u043D\u044B\u0445 \u043C\u0435\u0442\u0440\u043E\u0432).</p><p>\u0421 \u0442\u0435\u043C\u0438, \u043A\u0442\u043E \u0436\u0435\u043B\u0430\u0435\u0442 \u043D\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C, \u043D\u043E \u0438 \u0443\u0447\u0438\u0442\u044C \u0434\u0440\u0443\u0433\u0438\u0445 \u043D\u0430 \u0440\u0435\u0433\u0443\u043B\u044F\u0440\u043D\u043E\u0439 \u043E\u0441\u043D\u043E\u0432\u0435, \u043D\u0430\u0448 \u0443\u0447\u0435\u0431\u043D\u044B\u0439 \u0446\u0435\u043D\u0442\u0440 \u0438\u043C\u0435\u0435\u0442 \u0434\u043E\u0433\u043E\u0432\u043E\u0440\u043D\u044B\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044F. \u0410 \u0432 \u0446\u0435\u043B\u043E\u043C \u0432 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u043E\u043C \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0435, \u043A\u0430\u043A \u0438 \u0432 \u043B\u044E\u0431\u043E\u043C \u0434\u0440\u0443\u0433\u043E\u043C, \u0432\u0437\u0430\u0438\u043C\u043D\u043E\u0435 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u043E\u0431\u0449\u0435\u043D\u0438\u044F, \u043F\u043E \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0432\u044B\u0433\u043E\u0434\u043D\u043E\u043C\u0443 \u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0443 \u2013 \u0434\u0435\u043B\u0430\u0439 \u0434\u043E\u0431\u0440\u043E \u0434\u0440\u0443\u0433\u0438\u043C, \u0432 \u0442\u0440\u0443\u0434\u043D\u044B\u0439 \u043C\u043E\u043C\u0435\u043D\u0442 \u0442\u0435\u0431\u0435 \u0442\u043E\u0436\u0435 \u043F\u043E\u043C\u043E\u0433\u0443\u0442.</p><p>\u0412 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u0439 \u043C\u043E\u043C\u0435\u043D\u0442 \u0443 \u043D\u0430\u0441 \u043D\u0435\u0442 \u0435\u0434\u0438\u043D\u043E\u0439 \u043E\u0431\u0443\u0447\u0430\u044E\u0449\u0435\u0439 \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u044B \u0438\u043B\u0438 \u043A\u0430\u043A\u043E\u0433\u043E-\u0442\u043E \u0434\u043B\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u043A\u0443\u0440\u0441\u0430 (\u043A\u0440\u043E\u043C\u0435, \u0440\u0430\u0437\u0432\u0435 \u0447\u0442\u043E, \u043A\u0443\u0440\u0441\u0430 \u043F\u043E \u0440\u0430\u0431\u043E\u0442\u0435 \u0431\u043E\u0440-\u043C\u0430\u0448\u0438\u043D\u043A\u043E\u0439), \u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u043C \u0432\u0441\u0435 \u0437\u0430\u043D\u044F\u0442\u0438\u044F \u0440\u0430\u0437\u043E\u0432\u044B\u0435 \u0438 \u043A\u043B\u0430\u0441\u0441\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u044E\u0442\u0441\u044F \u043A\u0430\u043A \u043C\u0430\u0441\u0442\u0435\u0440-\u043A\u043B\u0430\u0441\u0441\u044B (\u0445\u043E\u0442\u044F \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 \u044D\u0442\u043E \u0441\u043A\u043E\u0440\u0435\u0435 \u0432\u043E\u0440\u043A-\u0448\u043E\u043F\u044B, \u043D\u043E \u044D\u0442\u043E \u043F\u043E\u043D\u044F\u0442\u0438\u0435 \u0443 \u043D\u0430\u0441 \u043F\u043E\u0447\u0435\u043C\u0443-\u0442\u043E \u043C\u0435\u043D\u0435\u0435 \u043F\u043E\u043F\u0443\u043B\u044F\u0440\u043D\u043E, \u0432\u0438\u0434\u0438\u043C\u043E, \u0438\u0437-\u0437\u0430 \u0441\u0432\u043E\u0435\u0439 \xAB\u0438\u043D\u043E\u0441\u0442\u0440\u0430\u043D\u043D\u043E\u0441\u0442\u0438\xBB). \u0422\u0430\u043A\u0438\u0435 \u0437\u0430\u043D\u044F\u0442\u0438\u044F \u0438\u0434\u0443\u0442 \u0434\u0435\u043D\u044C \u0438\u043B\u0438 \u0434\u0432\u0430 \u0434\u043D\u044F, \u043E\u0434\u043D\u043E \u0437\u0430\u043D\u044F\u0442\u0438\u0435 \u0432 \u0441\u0440\u0435\u0434\u043D\u0435\u043C \u0434\u043B\u0438\u0442\u0441\u044F 2-3 \u0447\u0430\u0441\u0430. \u0421\u0435\u0439\u0447\u0430\u0441 \u0447\u0435\u0440\u0435\u0437 \u0443\u0447\u0435\u0431\u043D\u044B\u0439 \u0446\u0435\u043D\u0442\u0440 \xAB\u0414\u0430\u0440 \u0442\u0440\u0443\u0434\u0430\xBB \u0432 \u0441\u0440\u0435\u0434\u043D\u0435\u043C \u0432 \u043C\u0435\u0441\u044F\u0446 \u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442 \u043E\u043A\u043E\u043B\u043E 80 \u0447\u0435\u043B\u043E\u0432\u0435\u043A.</p><p><img src="'+c+'" alt="" title="\u0414\u0430\u0440 \u0442\u0440\u0443\u0434\u0430"></p><p>\u041F\u043E\u0447\u0435\u043C\u0443 \u043B\u044E\u0434\u0438 \u043F\u043E\u0442\u044F\u043D\u0443\u043B\u0438\u0441\u044C \u0432 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u0435 \u0438 \u043F\u0440\u043E\u0447\u0438\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0435? \u041C\u043D\u0435 \u043A\u0430\u0436\u0435\u0442\u0441\u044F, \u044D\u0442\u043E \u0441\u0432\u044F\u0437\u0430\u043D\u043E \u0441 \u0432\u043E\u0437\u0432\u0440\u0430\u0449\u0435\u043D\u0438\u0435\u043C \u043A \u0438\u0441\u0442\u043E\u043A\u0430\u043C, \u0441\u043F\u0438\u0440\u0430\u043B\u044C \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u043B\u0430 \u043E\u0431\u043E\u0440\u043E\u0442 \u2013 \u043C\u044B \u043F\u0435\u0440\u0435\u0440\u043E\u0441\u043B\u0438 \u043C\u043E\u0434\u0443 \u043D\u0430 \xAB\u0440\u0430\u0431\u043E\u0442\u0443 \u0432 \u043E\u0444\u0438\u0441\u0435\xBB \u0438 \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u043F\u0435\u0440\u0435\u0440\u0430\u0441\u0442\u0430\u0435\u043C \u043C\u043E\u0434\u0443 \u043D\u0430 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u0435 \u043F\u043E\u0442\u0440\u0435\u0431\u043B\u0435\u043D\u0438\u0435 \u0432 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0438 \u0441\u043E\u0437\u0438\u0434\u0430\u043D\u0438\u044F. \u041B\u044E\u0434\u0438 \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0442 \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C, \u0447\u0442\u043E \u0441\u0438\u0434\u0435\u0442\u044C \u0432\u0435\u0441\u044C \u0434\u0435\u043D\u044C \u0432 \u043A\u0440\u0435\u0441\u043B\u0435 \u2013 \u0432\u0440\u0435\u0434\u043D\u043E, \u043D\u0435 \u0432\u0438\u0434\u0435\u0442\u044C \u043F\u0440\u0438 \u044D\u0442\u043E\u043C \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430 \u0441\u0432\u043E\u0435\u0433\u043E \u0442\u0440\u0443\u0434\u0430 \u2013 \u043F\u043E \u043C\u0435\u043D\u044C\u0448\u0435\u0439 \u043C\u0435\u0440\u0435, \u043E\u0431\u0438\u0434\u043D\u043E, \u0430 \u043F\u0435\u0440\u0441\u043F\u0435\u043A\u0442\u0438\u0432\u0430 \u043D\u0435 \u0441\u0443\u043C\u0435\u0442\u044C \u043D\u0438\u0447\u0435\u0433\u043E \u043E\u0442\u0432\u0435\u0442\u0438\u0442\u044C \u0432\u043D\u0443\u043A\u0430\u043C \u043D\u0430 \u0432\u043E\u043F\u0440\u043E\u0441 \xAB\u0414\u0435\u0434\u0443\u0448\u043A\u0430, \u0430 \u0447\u0442\u043E \u0442\u044B \u0441\u0434\u0435\u043B\u0430\u043B \u043F\u043E\u043B\u0435\u0437\u043D\u043E\u0433\u043E \u0432 \u0441\u0432\u043E\u0435\u0439 \u0436\u0438\u0437\u043D\u0438?\xBB \u043F\u0440\u043E\u0441\u0442\u043E \u0433\u0443\u0431\u0438\u0442\u0435\u043B\u044C\u043D\u0430.</p><p>\u0414\u0430, \u044D\u0442\u043E \u0438\u0437 \u0441\u0435\u0440\u0438\u0438 \xAB\u043F\u043E\u0441\u0430\u0434\u0438\u0442\u044C \u0434\u0435\u0440\u0435\u0432\u043E, \u043F\u043E\u0441\u0442\u0440\u043E\u0438\u0442\u044C \u0434\u043E\u043C \u0438 \u0432\u044B\u0440\u0430\u0441\u0442\u0438\u0442\u044C \u0441\u044B\u043D\u0430\xBB. \u041A \u0442\u043E\u043C\u0443 \u0436\u0435, \u044D\u043F\u043E\u0445\u0430 \u043A\u0440\u0438\u0437\u0438\u0441\u0430 \u0432\u0441\u0435\u0433\u0434\u0430 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u0432\u0435\u0434\u0451\u0442 \u043A \u0440\u043E\u0441\u0442\u0443 \u0434\u0432\u0443\u0445 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u0432: \u0440\u043E\u0436\u0434\u0430\u0435\u043C\u043E\u0441\u0442\u0438 \u0438 \u043F\u043E\u0438\u0441\u043A\u0430 \u0431\u043E\u043B\u0435\u0435 \u0432\u044B\u0433\u043E\u0434\u043D\u044B\u0445 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u0438\u0439. \u0421\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F (\u0445\u043E\u0442\u044C \u044D\u0442\u043E \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 \u0438 \u043D\u0435 \u0442\u0430\u043A), \u0447\u0442\u043E \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0447\u0442\u043E-\u0442\u043E \u0441\u0430\u043C\u043E\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u043D\u043E \u2013 \u0433\u043E\u0440\u0430\u0437\u0434\u043E \u0434\u0435\u0448\u0435\u0432\u043B\u0435, \u0447\u0435\u043C \u043A\u0443\u043F\u0438\u0442\u044C \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435 \u0432 \u043C\u0430\u0433\u0430\u0437\u0438\u043D\u0435. \u042D\u0442\u043E \u0432\u0441\u0451, \u043A\u0441\u0442\u0430\u0442\u0438, \u043E\u0431\u0449\u0435\u043C\u0438\u0440\u043E\u0432\u044B\u0435 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B, \u0432\u0435\u0434\u044C DIY \u0441\u0435\u0439\u0447\u0430\u0441 \u043F\u043E\u043F\u0443\u043B\u044F\u0440\u0435\u043D \u0432\u043E \u0432\u0441\u0451\u043C \u043C\u0438\u0440\u0435.</p><p>\u041C\u044B \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u043E \u043D\u0435 \u043F\u0440\u043E\u0432\u043E\u0434\u0438\u043B\u0438 \u043D\u0438\u043A\u0430\u043A\u0438\u0445 \u043F\u0438\u0430\u0440-\u0430\u043A\u0446\u0438\u0439 \u0438 \u0443\u0436 \u0442\u0435\u043C \u0431\u043E\u043B\u0435\u0435 \u2013 \u0440\u0435\u043A\u043B\u0430\u043C\u043D\u044B\u0445 \u043A\u0430\u043C\u043F\u0430\u043D\u0438\u0439. \u0418\u043D\u043E\u0433\u0434\u0430 \u043C\u044B \u0432\u044B\u043A\u043B\u0430\u0434\u044B\u0432\u0430\u0435\u043C \u043E\u0431\u044A\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u043E \u0441\u0434\u0430\u0447\u0435 \u0432 \u0430\u0440\u0435\u043D\u0434\u0443 \u0440\u0430\u0431\u043E\u0447\u0438\u0445 \u043C\u0435\u0441\u0442 \u043D\u0430 Avito, \u043D\u043E \u043C\u0435\u043D\u044C\u0448\u0435 \u0447\u0435\u043C \u0447\u0435\u0440\u0435\u0437 \u043D\u0435\u0434\u0435\u043B\u044E \u0441\u043D\u0438\u043C\u0430\u0435\u043C \u0435\u0433\u043E, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0435 \u043C\u0435\u0441\u0442\u0430 \u0442\u0443\u0442 \u0436\u0435 \u0437\u0430\u043F\u043E\u043B\u043D\u044F\u044E\u0442\u0441\u044F. \u0412\u043E\u043E\u0431\u0449\u0435 \u043D\u0430\u0448 \u0433\u043B\u0430\u0432\u043D\u044B\u0439 \u0440\u0435\u043A\u043B\u0430\u043C\u043D\u044B\u0439 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442 \u2013 \u044D\u0442\u043E \xAB\u0441\u0430\u0440\u0430\u0444\u0430\u043D\u043D\u043E\u0435 \u0440\u0430\u0434\u0438\u043E\xBB, \u0438 \u043B\u0443\u0447\u0448\u0435 \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435 \u043F\u0440\u0438\u0434\u0443\u043C\u0430\u0435\u0448\u044C.</p><p><img src="'+_+'" alt="" title="\u0414\u0430\u0440 \u0442\u0440\u0443\u0434\u0430"></p><p><strong>\u0427\u0442\u043E \u0434\u0430\u043B\u044C\u0448\u0435</strong></p><p>\u0421\u0430\u043C\u044B\u0435 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u0437\u0430\u0442\u0440\u0430\u0442\u044B \u0432 \u043D\u0430\u0448\u0435\u043C \u0434\u0435\u043B\u0435 \u2013 \u0430\u0440\u0435\u043D\u0434\u0430 \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u0439. \u0422\u0430\u043A\u0436\u0435 \u0434\u043E\u0432\u043E\u043B\u044C\u043D\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0437\u0430\u0442\u0440\u0430\u0442\u044B \u0431\u044B\u043B\u0438 \u043D\u0430 \u0437\u0430\u043A\u0443\u043F\u043A\u0443 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F, \u043D\u043E \u044D\u0442\u043E \u0431\u044B\u043B\u0438 \u0440\u0430\u0437\u043E\u0432\u044B\u0435 \u0440\u0430\u0441\u0445\u043E\u0434\u044B, \u0441\u0435\u0439\u0447\u0430\u0441 \u043D\u0435\u0442 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0441\u0442\u0438 \u043A\u0440\u0443\u043F\u043D\u043E \u0438\u043D\u0432\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0432 \u0441\u0442\u0430\u043D\u043A\u0438 \u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B.</p><p>\u0412 \u043F\u0440\u043E\u0435\u043A\u0442\u0435 \u0437\u0430\u0434\u0435\u0439\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u043E \u0447\u0443\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u0435 15 \u0447\u0435\u043B\u043E\u0432\u0435\u043A: \u0434\u0432\u0430 \u0441\u043E\u043E\u0441\u043D\u043E\u0432\u0430\u0442\u0435\u043B\u044F, \u0442\u0440\u0438 \u0430\u0434\u043C\u0438\u043D\u0438\u0441\u0442\u0440\u0430\u0442\u043E\u0440\u0430 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430, \u0434\u0432\u0430 \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0441\u0442\u0430 \u043F\u043E \u0440\u0435\u043C\u043E\u043D\u0442\u0443 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F, \u0440\u0443\u043A\u043E\u0432\u043E\u0434\u0438\u0442\u0435\u043B\u044C \u0443\u0447\u0435\u0431\u043D\u043E\u0433\u043E \u0446\u0435\u043D\u0442\u0440\u0430, \u043F\u043E \u0442\u0440\u0438 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u0432 \u043B\u0430\u0437\u0435\u0440\u043D\u043E\u043C \u0438 \u0444\u0440\u0435\u0437\u0435\u0440\u043D\u043E\u043C \u0446\u0435\u0445\u0430\u0445, \u043F\u0430\u0440\u0430 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u0445 \u0432\u043E\u043B\u043E\u043D\u0442\u0451\u0440\u043E\u0432 \u0438\u2026 \u044F, \u0420\u043E\u043C\u0430\u043D \u0411\u043E\u043D\u0434\u0430\u0440\u0435\u0432.</p><p>\u042F \u044F\u0432\u043B\u044F\u044E\u0441\u044C \u0441\u0442\u0430\u0440\u0435\u0439\u0448\u0438\u043C \u0440\u0435\u0437\u0438\u0434\u0435\u043D\u0442\u043E\u043C \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439, \u043F\u043E\u043F\u0430\u043B \u0432 \u043D\u0435\u0451 \u0447\u0435\u0440\u0435\u0437 \u0434\u0432\u0435 \u043D\u0435\u0434\u0435\u043B\u0438 \u043F\u043E\u0441\u043B\u0435 \u043E\u0442\u043A\u0440\u044B\u0442\u0438\u044F. \u0421 \u0441\u0430\u043C\u043E\u0433\u043E \u043D\u0430\u0447\u0430\u043B\u0430 \u043D\u0430\u0448\u0435\u0433\u043E \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u0430\u043A\u0442\u0438\u0432\u043D\u043E \u0443\u0447\u0430\u0441\u0442\u0432\u043E\u0432\u0430\u043B \u0432 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0435 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u0432 \u043F\u043E \u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u044E \u0438 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044E, \u0431\u044B\u043B \u043F\u0435\u0440\u0432\u044B\u043C \u0430\u0434\u043C\u0438\u043D\u0438\u0441\u0442\u0440\u0430\u0442\u043E\u0440\u043E\u043C \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430. \u0421\u0435\u0439\u0447\u0430\u0441 \u0441\u043E\u0432\u043C\u0435\u0449\u0430\u044E \u0444\u0443\u043D\u043A\u0446\u0438\u0438 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0441\u0442\u0430 \u043F\u043E \u0441\u0432\u044F\u0437\u044F\u043C \u0441 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E, \u043A\u043E\u043F\u0438\u0440\u0430\u0439\u0442\u0435\u0440\u0430, \u0432 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435 \u0434\u0438\u0437\u0430\u0439\u043D\u0435\u0440\u0430, \u0438\u043D\u043E\u0433\u0434\u0430 \u043C\u043E\u0434\u0435\u0440\u0430\u0442\u043E\u0440\u0430 \u0441\u043E\u0431\u0440\u0430\u043D\u0438\u0439, \u043A\u0443\u0440\u0430\u0442\u043E\u0440\u0430 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0439 \u0438 \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u0430 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0430 \u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u0439, \u0430 \u0442\u0430\u043A\u0436\u0435 \xAB\u0433\u0440\u0430\u0434\u0443\u0441\u043D\u0438\u043A\u0430 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439\xBB \u2013 \u0431\u0443\u0434\u0443\u0447\u0438 100%-\u043D\u044B\u043C \u0438\u043D\u0441\u0430\u0439\u0434\u0435\u0440\u043E\u043C, \u043E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u044E \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u043D\u0430\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u044F. \u041F\u043E\u043C\u0438\u043C\u043E \u044D\u0442\u043E\u0433\u043E, \u0437\u0430\u043D\u0438\u043C\u0430\u044E\u0441\u044C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u043E\u0439 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E \u2013 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u044E \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u0437\u0430\u043A\u0430\u0437\u044B, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u044E \u043B\u0438\u0447\u043D\u044B\u0435 \u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u043E-\u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u043F\u0440\u043E\u0435\u043A\u0442\u044B.</p><p>\u041F\u043B\u0430\u043D\u044B \u043F\u043E \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044E \u0433\u0440\u0430\u043D\u0434\u0438\u043E\u0437\u043D\u044B. \u0412 \u043D\u0438\u0445 \u0438 \u043E\u0442\u043A\u0440\u044B\u0442\u0438\u0435 \u0444\u0440\u0430\u043D\u0447\u0430\u0439\u0437\u0438\u043D\u0433\u043E\u0432\u043E\u0433\u043E \u043F\u0440\u043E\u0435\u043A\u0442\u0430, \u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435 \u043F\u043B\u043E\u0449\u0430\u0434\u0435\u0439, \u0438 \u043D\u043E\u0432\u044B\u0435 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u0438 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0435 \u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u043E\u0433\u043E \u043A\u043B\u0430\u0441\u0442\u0435\u0440\u0430. \u041D\u043E \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u043E\u0431 \u044D\u0442\u043E\u043C \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0442\u044C \u043F\u043E\u043A\u0430 \u0440\u0430\u043D\u043E.</p><p><img src="'+d+'" alt="" title="\u0420\u043E\u043C\u0430\u043D \u0411\u043E\u043D\u0434\u0430\u0440\u0435\u0432"></p><p><a href="https://biz360.ru/materials/svoimi-rukami-kak-ustroen-stolyarnyy-kovorking-dlya-lyubiteley-i-professionalov/" class="external-link" target="_blank" rel="noopener noreferrer">\u041E\u0440\u0438\u0433\u0438\u043D\u0430\u043B \u0441\u0442\u0430\u0442\u044C\u0438 \u043D\u0430 biz360.ru</a></p>',50),f=[l];function m(b,h,v,u,k,j){return e(),t("div",null,f)}var T=p(g,[["render",m]]);export{y as __pageData,T as default};
